{
  "name": "Slender: The React Awakening",
  "description": "A high-fidelity 3D horror experience built with React and Three.js. Collect 8 pages while avoiding the Slender Man. Features dynamic atmosphere and AI-generated cryptic messages.",
  "requestFramePermissions": ["camera"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GameState {
  pagesCollected: number;
  isGameOver: boolean;
  isWon: boolean;
  flashlightOn: boolean;
  staticIntensity: number;
  lastMessage: string;
  gameStarted: boolean;
}

export interface Page {
  id: string;
  position: [number, number, number];
  collected: boolean;
}

export enum GameStatus {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  VICTORY = 'VICTORY'
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getCrypticMessage = async (pageCount: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a very short, cryptic, and terrifying one-sentence message that Slender Man would leave on a note. The player has collected ${pageCount} out of 8 pages. Keep it under 10 words.`,
      config: {
        temperature: 0.9,
        topP: 0.95,
      },
    });
    return response.text || "ALWAYS WATCHES, NO EYES.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "HE IS HERE.";
  }
};

export const getDeathMessage = async (): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "The player has been caught by Slender Man in the woods. Write a short, chilling death message.",
      config: {
        temperature: 1,
      },
    });
    return response.text || "YOU COULDN'T RUN FAST ENOUGH.";
  } catch (error) {
    return "GAME OVER";
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameStatus } from './types';
import { getCrypticMessage, getDeathMessage } from './services/gemini';
import GameScene from './components/GameScene';
import UI from './components/UI';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.MENU);
  const [pages, setPages] = useState(0);
  const [flashlight, setFlashlight] = useState(true);
  const [staticAmount, setStaticAmount] = useState(0);
  const [message, setMessage] = useState<string>('');
  const [deathNote, setDeathNote] = useState<string>('');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    // Initial creepy message
    if (status === GameStatus.PLAYING) {
      setMessage("FIND THE 8 PAGES");
      setTimeout(() => setMessage(''), 5000);
    }
  }, [status]);

  const handlePageCollect = useCallback(async () => {
    const nextPages = pages + 1;
    setPages(nextPages);

    if (nextPages === 8) {
      setStatus(GameStatus.VICTORY);
      return;
    }

    // Dynamic spooky text from Gemini
    const cryptic = await getCrypticMessage(nextPages);
    setMessage(cryptic);
    setTimeout(() => setMessage(''), 4000);
  }, [pages]);

  const handleDeath = useCallback(async () => {
    setStatus(GameStatus.GAME_OVER);
    const note = await getDeathMessage();
    setDeathNote(note);
  }, []);

  const startGame = () => {
    setPages(0);
    setStaticAmount(0);
    setStatus(GameStatus.PLAYING);
    setFlashlight(true);
    setMessage('');
  };

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <div className="crt-overlay" />
      <div className="noise" style={{ opacity: Math.max(0.05, staticAmount * 0.8) }} />

      {status === GameStatus.PLAYING && (
        <GameScene 
          pagesCollected={pages}
          flashlightOn={flashlight}
          onCollectPage={handlePageCollect}
          onDeath={handleDeath}
          setStaticAmount={setStaticAmount}
        />
      )}

      <UI 
        status={status}
        pages={pages}
        message={message}
        deathNote={deathNote}
        onStart={startGame}
        flashlightOn={flashlight}
        toggleFlashlight={() => setFlashlight(!flashlight)}
      />

      <div className="fixed bottom-4 left-4 text-[10px] text-zinc-700 uppercase tracking-widest z-50">
        WASD to Move | Mouse to Look | F to Flashlight | Esc to Menu
      </div>
    </div>
  );
};

export default App;

import React, { Suspense, useRef, useState, useEffect, useMemo } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { PointerLockControls, Sky, Stars, PerspectiveCamera, Cloud, useHelper } from '@react-three/drei';
import * as THREE from 'three';

// -- Helper Components --

const Tree = ({ position }: { position: [number, number, number] }) => {
  return (
    <group position={position}>
      {/* Trunk */}
      <mesh position={[0, 2.5, 0]}>
        <cylinderGeometry args={[0.3, 0.5, 5, 8]} />
        <meshStandardMaterial color="#1a120b" roughness={1} />
      </mesh>
      {/* Leaves (Spiky for horror feel) */}
      <mesh position={[0, 5, 0]}>
        <coneGeometry args={[2, 6, 6]} />
        <meshStandardMaterial color="#0b1a0e" roughness={1} />
      </mesh>
    </group>
  );
};

const Page = ({ position, onCollect }: { position: [number, number, number], onCollect: () => void }) => {
  const [collected, setCollected] = useState(false);
  const ref = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (collected) return;
    const distance = state.camera.position.distanceTo(new THREE.Vector3(...position));
    if (distance < 2) {
      setCollected(true);
      onCollect();
    }
  });

  if (collected) return null;

  return (
    <mesh position={position} rotation={[0, Math.random() * Math.PI, 0]} ref={ref}>
      <planeGeometry args={[0.4, 0.6]} />
      <meshBasicMaterial color="white" side={THREE.DoubleSide} />
    </mesh>
  );
};

const SlenderMan = ({ position, playerPos }: { position: THREE.Vector3, playerPos: THREE.Vector3 }) => {
  return (
    <group position={[position.x, 0, position.z]}>
      {/* Body */}
      <mesh position={[0, 2, 0]}>
        <boxGeometry args={[0.4, 4, 0.2]} />
        <meshBasicMaterial color="black" />
      </mesh>
      {/* Head */}
      <mesh position={[0, 4.2, 0]}>
        <sphereGeometry args={[0.25, 16, 16]} />
        <meshBasicMaterial color="#e0e0e0" />
      </mesh>
      {/* Long Arms */}
      <mesh position={[0.4, 2.5, 0]} rotation={[0, 0, -0.2]}>
        <boxGeometry args={[0.1, 3.5, 0.1]} />
        <meshBasicMaterial color="black" />
      </mesh>
      <mesh position={[-0.4, 2.5, 0]} rotation={[0, 0, 0.2]}>
        <boxGeometry args={[0.1, 3.5, 0.1]} />
        <meshBasicMaterial color="black" />
      </mesh>
    </group>
  );
};

const Forest = ({ pagesCollected, onCollectPage }: { pagesCollected: number, onCollectPage: () => void }) => {
  const trees = useMemo(() => {
    return Array.from({ length: 150 }).map((_, i) => ({
      id: i,
      pos: [
        (Math.random() - 0.5) * 100,
        0,
        (Math.random() - 0.5) * 100
      ] as [number, number, number]
    }));
  }, []);

  const pagePositions = useMemo(() => {
    // Distribute pages far apart
    return [
      [20, 1, 20], [-30, 1, 15], [10, 1, -40], [-45, 1, -20],
      [40, 1, -10], [5, 1, 45], [-15, 1, -15], [35, 1, 35]
    ] as [number, number, number][];
  }, []);

  return (
    <>
      <mesh rotation={[-Math.PI / 2, 0, 0]} receiveShadow position={[0, 0, 0]}>
        <planeGeometry args={[200, 200]} />
        <meshStandardMaterial color="#050505" roughness={1} />
      </mesh>
      {trees.map(t => <Tree key={t.id} position={t.pos} />)}
      {pagePositions.map((pos, i) => (
        <Page key={i} position={pos} onCollect={onCollectPage} />
      ))}
    </>
  );
};

const Controller = ({ onDeath, setStaticAmount, pagesCollected, flashlightOn }: any) => {
  const { camera } = useThree();
  const moveSpeed = 0.15;
  const keys = useRef<{ [key: string]: boolean }>({});
  const slenderPos = useRef(new THREE.Vector3(50, 0, 50));
  const lastTeleport = useRef(0);

  useEffect(() => {
    const down = (e: KeyboardEvent) => keys.current[e.code] = true;
    const up = (e: KeyboardEvent) => keys.current[e.code] = false;
    window.addEventListener('keydown', down);
    window.addEventListener('keyup', up);
    return () => {
      window.removeEventListener('keydown', down);
      window.removeEventListener('keyup', up);
    };
  }, []);

  useFrame((state, delta) => {
    // Movement logic
    const direction = new THREE.Vector3();
    const frontVector = new THREE.Vector3(0, 0, Number(keys.current['KeyS']) - Number(keys.current['KeyW']));
    const sideVector = new THREE.Vector3(Number(keys.current['KeyA']) - Number(keys.current['KeyD']), 0, 0);

    direction
      .subVectors(frontVector, sideVector)
      .normalize()
      .multiplyScalar(moveSpeed)
      .applyQuaternion(camera.quaternion);

    camera.position.x += direction.x;
    camera.position.z += direction.z;
    camera.position.y = 1.7; // Fixed height

    // Slender AI
    const dist = camera.position.distanceTo(slenderPos.current);

    // Static effect based on distance and looking
    const lookDir = new THREE.Vector3();
    camera.getWorldDirection(lookDir);
    const toSlender = new THREE.Vector3().subVectors(slenderPos.current, camera.position).normalize();
    const dot = lookDir.dot(toSlender);

    let currentStatic = 0;
    if (dist < 20) {
      // More pages = more aggressive static
      const multiplier = 1 + (pagesCollected * 0.5);
      currentStatic = (Math.max(0, (20 - dist) / 20) * multiplier);
      if (dot > 0.8) {
        currentStatic *= 3;
      }
    }
    setStaticAmount(Math.min(1, currentStatic));

    if (dist < 2.5) {
      onDeath();
    }

    // Teleportation logic
    const now = state.clock.getElapsedTime();
    const teleportCooldown = Math.max(2, 10 - pagesCollected);

    // Slender teleports when player isn't looking or after some time
    if (now - lastTeleport.current > teleportCooldown || (dist > 30 && dot < 0)) {
      const angle = Math.random() * Math.PI * 2;
      const spawnDist = Math.max(8, 25 - pagesCollected * 2);
      slenderPos.current.set(
        camera.position.x + Math.cos(angle) * spawnDist,
        0,
        camera.position.z + Math.sin(angle) * spawnDist
      );
      lastTeleport.current = now;
    }
  });

  return (
    <>
      <PointerLockControls />
      <SlenderMan position={slenderPos.current} playerPos={camera.position} />
      <spotLight 
        position={[0, 0, 0]} 
        intensity={flashlightOn ? 25 : 0} 
        distance={20} 
        angle={0.4} 
        penumbra={0.5} 
        color="#fff4e0"
        castShadow
        target={camera} // This might need a ref to work perfectly but in Fiber we can cheat
      />
      <primitive object={camera} />
    </>
  );
};

// -- Main Scene Component --

interface GameSceneProps {
  pagesCollected: number;
  flashlightOn: boolean;
  onCollectPage: () => void;
  onDeath: () => void;
  setStaticAmount: (val: number) => void;
}

const GameScene: React.FC<GameSceneProps> = (props) => {
  return (
    <div className="w-full h-full">
      <Canvas shadows camera={{ fov: 65 }}>
        <color attach="background" args={['#000']} />
        <fog attach="fog" args={['#000', 1, 25]} />

        <Suspense fallback={null}>
          <ambientLight intensity={0.02} />
          <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />

          <Forest 
            pagesCollected={props.pagesCollected} 
            onCollectPage={props.onCollectPage} 
          />

          <Controller {...props} />
        </Suspense>
      </Canvas>
    </div>
  );
};

export default GameScene;

import React from 'react';
import { GameStatus } from '../types';

interface UIProps {
  status: GameStatus;
  pages: number;
  message: string;
  deathNote: string;
  onStart: () => void;
  flashlightOn: boolean;
  toggleFlashlight: () => void;
}

const UI: React.FC<UIProps> = ({ status, pages, message, deathNote, onStart, flashlightOn, toggleFlashlight }) => {

  if (status === GameStatus.MENU) {
    return (
      <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/90 z-40 p-6 text-center">
        <h1 className="text-6xl md:text-8xl font-bold tracking-[0.2em] mb-4 text-zinc-100 uppercase opacity-80">SLENDER</h1>
        <p className="text-zinc-500 max-w-md mb-12 uppercase tracking-widest text-sm leading-relaxed">
          The woods are cold. The pages are calling. Do not look at him.
        </p>
        <button 
          onClick={onStart}
          className="border border-zinc-700 hover:border-zinc-200 hover:bg-zinc-100 hover:text-black transition-all px-12 py-4 uppercase tracking-[0.3em] text-lg"
        >
          Collect the Pages
        </button>
      </div>
    );
  }

  if (status === GameStatus.GAME_OVER) {
    return (
      <div className="absolute inset-0 flex flex-col items-center justify-center bg-black z-50 text-center p-8">
        <div className="w-full h-full absolute inset-0 bg-white/5 animate-pulse" />
        <h2 className="text-5xl font-bold mb-8 text-red-900 uppercase tracking-tighter">YOU DIED</h2>
        <p className="text-zinc-400 italic mb-12 max-w-lg">"{deathNote || 'He was always watching.'}"</p>
        <button 
          onClick={onStart}
          className="border border-red-900 text-red-900 px-8 py-3 uppercase tracking-widest hover:bg-red-950 hover:text-white transition-colors"
        >
          Try Again
        </button>
      </div>
    );
  }

  if (status === GameStatus.VICTORY) {
    return (
      <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-100 z-50 text-center">
        <h2 className="text-6xl font-bold mb-4 text-black uppercase tracking-tighter">SURVIVOR</h2>
        <p className="text-zinc-700 mb-8 uppercase tracking-widest">You collected all 8 pages.</p>
        <button 
          onClick={onStart}
          className="bg-black text-white px-8 py-3 uppercase tracking-widest hover:bg-zinc-800 transition-colors"
        >
          Return to Woods
        </button>
      </div>
    );
  }

  return (
    <div className="absolute inset-0 pointer-events-none z-30 p-10 flex flex-col justify-between">
      {/* Top HUD */}
      <div className="flex justify-between items-start">
        <div className="space-y-1">
          <div className="text-xs text-zinc-600 uppercase tracking-widest">Progress</div>
          <div className="text-2xl font-bold tracking-tighter opacity-70">
            {pages} <span className="text-zinc-700">/ 8</span>
          </div>
        </div>
        <div className="text-right">
          <div className="text-[10px] text-zinc-700 uppercase tracking-widest">Flashlight</div>
          <div className={`text-xs uppercase font-bold ${flashlightOn ? 'text-green-900' : 'text-zinc-800'}`}>
            {flashlightOn ? 'ACTIVE' : 'OFF'}
          </div>
        </div>
      </div>

      {/* Cryptic Message */}
      {message && (
        <div className="flex items-center justify-center">
          <div className="text-xl md:text-3xl font-black uppercase tracking-[0.4em] text-white animate-pulse text-center">
            {message}
          </div>
        </div>
      )}

      {/* Bottom HUD - Hidden, just for layout */}
      <div className="opacity-0">.</div>
    </div>
  );
};

export default UI;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameStatus } from './types';
import { getCrypticMessage, getDeathMessage } from './services/gemini';
import GameScene from './components/GameScene';
import UI from './components/UI';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.MENU);
  const [pages, setPages] = useState(0);
  const [flashlight, setFlashlight] = useState(true);
  const [staticAmount, setStaticAmount] = useState(0);
  const [message, setMessage] = useState<string>('');
  const [deathNote, setDeathNote] = useState<string>('');

  useEffect(() => {
    // Initial creepy message
    if (status === GameStatus.PLAYING) {
      setMessage("FIND THE 8 PAGES");
      const timer = setTimeout(() => setMessage(''), 5000);
      return () => clearTimeout(timer);
    }
  }, [status]);

  useEffect(() => {
    const handleGlobalKeys = (e: KeyboardEvent) => {
      if (e.code === 'KeyF' && status === GameStatus.PLAYING) {
        setFlashlight(prev => !prev);
      }
      if (e.code === 'KeyG') {
        setStatus(prev => prev === GameStatus.PLAYING ? GameStatus.MENU : prev);
      }
    };

    window.addEventListener('keydown', handleGlobalKeys);
    return () => window.removeEventListener('keydown', handleGlobalKeys);
  }, [status]);

  const handlePageCollect = useCallback(async () => {
    const nextPages = pages + 1;
    setPages(nextPages);

    if (nextPages === 8) {
      setStatus(GameStatus.VICTORY);
      return;
    }

    // Dynamic spooky text from Gemini
    const cryptic = await getCrypticMessage(nextPages);
    setMessage(cryptic);
    setTimeout(() => setMessage(''), 4000);
  }, [pages]);

  const handleDeath = useCallback(async () => {
    setStatus(GameStatus.GAME_OVER);
    const note = await getDeathMessage();
    setDeathNote(note);
  }, []);

  const startGame = () => {
    setPages(0);
    setStaticAmount(0);
    setStatus(GameStatus.PLAYING);
    setFlashlight(true);
    setMessage('');
  };

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <div className="crt-overlay" />
      <div className="noise" style={{ opacity: Math.max(0.05, staticAmount * 0.8) }} />

      {status === GameStatus.PLAYING && (
        <GameScene 
          pagesCollected={pages}
          flashlightOn={flashlight}
          onCollectPage={handlePageCollect}
          onDeath={handleDeath}
          setStaticAmount={setStaticAmount}
        />
      )}

      <UI 
        status={status}
        pages={pages}
        message={message}
        deathNote={deathNote}
        onStart={startGame}
        flashlightOn={flashlight}
        toggleFlashlight={() => setFlashlight(!flashlight)}
      />

      <div className="fixed bottom-4 left-4 text-[10px] text-zinc-500 uppercase tracking-widest z-50 bg-black/50 px-2 py-1 rounded">
        WASD to Move | Mouse to Look | F for Flashlight | G for Menu
      </div>
    </div>
  );
};

export default App;

import React, { Suspense, useRef, useState, useEffect, useMemo } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { PointerLockControls, Stars } from '@react-three/drei';
import * as THREE from 'three';

// -- Helper Components --

const Tree = ({ position }: { position: [number, number, number] }) => {
  return (
    <group position={position}>
      <mesh position={[0, 2.5, 0]} castShadow>
        <cylinderGeometry args={[0.3, 0.5, 5, 8]} />
        <meshStandardMaterial color="#1a120b" roughness={1} />
      </mesh>
