          <ambientLight intensity={0.06} />
          <Stars radius={100} depth={50} count={3000} factor={4} saturation={0} fade speed={0.5} />

          <Forest onCollectPage={handlePageCollect} activePagePositions={activeVecs} />

          <Controller {...props} activePagePositions={activeVecs} />
        </Suspense>
      </Canvas>
    </div>
  );
};

export default GameScene;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameStatus } from './types';
import { getCrypticMessage, getDeathMessage } from './services/gemini';
import GameScene from './components/GameScene';
import UI from './components/UI';

const App: React.FC = () => {
  const [status, setStatus] = useState<GameStatus>(GameStatus.MENU);
  const [pages, setPages] = useState(0);
  const [flashlight, setFlashlight] = useState(true);
  const [staticAmount, setStaticAmount] = useState(0);
  const [message, setMessage] = useState<string>('');
  const [deathNote, setDeathNote] = useState<string>('');
  const [nearestPageAngle, setNearestPageAngle] = useState<number | null>(null);

  useEffect(() => {
    // Initial creepy message
    if (status === GameStatus.PLAYING) {
      setMessage("FIND THE 8 PAGES");
      const timer = setTimeout(() => setMessage(''), 5000);
      return () => clearTimeout(timer);
    }
  }, [status]);

  useEffect(() => {
    const handleGlobalKeys = (e: KeyboardEvent) => {
      if (e.code === 'KeyF' && status === GameStatus.PLAYING) {
        setFlashlight(prev => !prev);
      }
      if (e.code === 'KeyG') {
        setStatus(prev => prev === GameStatus.PLAYING ? GameStatus.MENU : prev);
      }
    };

    window.addEventListener('keydown', handleGlobalKeys);
    return () => window.removeEventListener('keydown', handleGlobalKeys);
  }, [status]);

  const handlePageCollect = useCallback(async () => {
    const nextPages = pages + 1;
    setPages(nextPages);

    if (nextPages === 8) {
      setStatus(GameStatus.VICTORY);
      return;
    }

    // Dynamic spooky text from Gemini
    const cryptic = await getCrypticMessage(nextPages);
    setMessage(cryptic);
    setTimeout(() => setMessage(''), 4000);
  }, [pages]);

  const handleDeath = useCallback(async () => {
    setStatus(GameStatus.GAME_OVER);
    const note = await getDeathMessage();
    setDeathNote(note);
  }, []);

  const startGame = () => {
    setPages(0);
    setStaticAmount(0);
    setStatus(GameStatus.PLAYING);
    setFlashlight(true);
    setMessage('');
    setNearestPageAngle(null);
  };

  return (
    <div className="relative w-full h-full bg-black overflow-hidden select-none">
      <div className="crt-overlay" />
      <div className="noise" style={{ opacity: Math.max(0.05, staticAmount * 0.8) }} />

      {status === GameStatus.PLAYING && (
        <GameScene 
          pagesCollected={pages}
          flashlightOn={flashlight}
          onCollectPage={handlePageCollect}
          onDeath={handleDeath}
          setStaticAmount={setStaticAmount}
          onUpdateNearestAngle={setNearestPageAngle}
        />
      )}

      <UI 
        status={status}
        pages={pages}
        message={message}
        deathNote={deathNote}
        onStart={startGame}
        flashlightOn={flashlight}
        toggleFlashlight={() => setFlashlight(!flashlight)}
        nearestPageAngle={nearestPageAngle}
      />

      <div className="fixed bottom-4 left-4 text-[10px] text-zinc-500 uppercase tracking-widest z-50 bg-black/50 px-2 py-1 rounded">
        WASD to Move | Mouse to Look | F for Flashlight | G for Menu
      </div>
    </div>
  );
};

export default App;

import React, { Suspense, useRef, useState, useEffect, useMemo } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { PointerLockControls, Stars } from '@react-three/drei';
import * as THREE from 'three';

// -- Helper Components --

const Tree = ({ position }: { position: [number, number, number] }) => {
  return (
    <group position={position}>
      <mesh position={[0, 2.5, 0]} castShadow>
        <cylinderGeometry args={[0.3, 0.5, 5, 8]} />
        <meshStandardMaterial color="#1a120b" roughness={1} />
      </mesh>
      <mesh position={[0, 5, 0]} castShadow>
        <coneGeometry args={[2, 6, 6]} />
        <meshStandardMaterial color="#0b1a0e" roughness={1} />
      </mesh>
    </group>
  );
};

const Shack = ({ position, rotation = 0 }: { position: [number, number, number], rotation?: number }) => {
  return (
    <group position={position} rotation={[0, rotation, 0]}>
      <mesh position={[0, 1.5, 0]} castShadow receiveShadow>
        <boxGeometry args={[4, 3, 4]} />
        <meshStandardMaterial color="#2a1f1a" roughness={1} />
      </mesh>
      <mesh position={[0, 3.5, 0]} rotation={[0, Math.PI / 4, 0]} castShadow>
        <coneGeometry args={[3.5, 2, 4]} />
        <meshStandardMaterial color="#1a1a1a" roughness={1} />
      </mesh>
      <mesh position={[0, 1, 2.01]}>
        <planeGeometry args={[1.2, 2]} />
        <meshBasicMaterial color="#000" />
      </mesh>
    </group>
  );
};

const Wall = ({ position, rotation = 0 }: { position: [number, number, number], rotation?: number }) => {
  return (
    <mesh position={position} rotation={[0, rotation, 0]} castShadow receiveShadow>
      <boxGeometry args={[6, 2, 0.5]} />
      <meshStandardMaterial color="#1a1a1a" roughness={1} />
    </mesh>
  );
};

const DirectionalArrow = ({ position, pagePositions }: { position: [number, number, number], pagePositions: THREE.Vector3[] }) => {
  const arrowRef = useRef<THREE.Group>(null);

  useFrame(() => {
    if (!arrowRef.current || pagePositions.length === 0) return;

    let closestPage = pagePositions[0];
    let minDist = arrowRef.current.position.distanceTo(closestPage);

    for (let i = 1; i < pagePositions.length; i++) {
      const d = arrowRef.current.position.distanceTo(pagePositions[i]);
      if (d < minDist) {
        minDist = d;
        closestPage = pagePositions[i];
      }
    }

    const target = new THREE.Vector3().copy(closestPage);
    target.y = position[1];
    arrowRef.current.lookAt(target);
  });

  return (
    <group ref={arrowRef} position={position}>
      <mesh rotation={[Math.PI / 2, 0, 0]}>
        <cylinderGeometry args={[0.05, 0.05, 0.8, 8]} />
        <meshStandardMaterial color="#ff0000" emissive="#330000" />
      </mesh>
      <mesh position={[0, 0, 0.5]} rotation={[Math.PI / 2, 0, 0]}>
        <coneGeometry args={[0.2, 0.3, 8]} />
        <meshStandardMaterial color="#ff0000" emissive="#330000" />
      </mesh>
    </group>
  );
};

const Page = ({ position, onCollect }: { position: [number, number, number], onCollect: () => void }) => {
  const [collected, setCollected] = useState(false);
  const ref = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (collected) return;
    const distance = state.camera.position.distanceTo(new THREE.Vector3(...position));
    if (distance < 2.5) {
      setCollected(true);
      onCollect();
    }
  });

  if (collected) return null;

  return (
    <mesh position={position} rotation={[0, Math.random() * Math.PI, 0]} ref={ref}>
      <planeGeometry args={[0.4, 0.6]} />
      <meshBasicMaterial color="white" side={THREE.DoubleSide} transparent opacity={0.9} />
    </mesh>
  );
};

const SlenderMan = ({ position }: { position: THREE.Vector3 }) => {
  return (
    <group position={[position.x, 0, position.z]}>
      <mesh position={[0, 2, 0]}>
        <boxGeometry args={[0.4, 4, 0.2]} />
        <meshBasicMaterial color="black" />
      </mesh>
      <mesh position={[0, 4.2, 0]}>
        <sphereGeometry args={[0.25, 16, 16]} />
        <meshBasicMaterial color="#d0d0d0" />
      </mesh>
      <mesh position={[0.4, 2.5, 0]} rotation={[0, 0, -0.1]}>
        <boxGeometry args={[0.1, 3.8, 0.1]} />
        <meshBasicMaterial color="black" />
      </mesh>
      <mesh position={[-0.4, 2.5, 0]} rotation={[0, 0, 0.1]}>
        <boxGeometry args={[0.1, 3.8, 0.1]} />
        <meshBasicMaterial color="black" />
      </mesh>
    </group>
  );
};

const Forest = ({ onCollectPage, activePagePositions }: { onCollectPage: (id: number) => void, activePagePositions: THREE.Vector3[] }) => {
  const trees = useMemo(() => {
    return Array.from({ length: 200 }).map((_, i) => ({
      id: i,
      pos: [
        (Math.random() - 0.5) * 140,
        0,
        (Math.random() - 0.5) * 140
      ] as [number, number, number]
    }));
  }, []);

  const pageDefinitions = useMemo(() => {
    return [
      { id: 0, pos: [20, 1.2, 20] }, 
      { id: 1, pos: [-35, 1.2, 18] }, 
      { id: 2, pos: [12, 1.2, -45] }, 
      { id: 3, pos: [-50, 1.2, -25] },
      { id: 4, pos: [45, 1.2, -12] }, 
      { id: 5, pos: [8, 1.2, 50] }, 
      { id: 6, pos: [-18, 1.2, -18] }, 
      { id: 7, pos: [38, 1.2, 38] }
    ] as { id: number, pos: [number, number, number] }[];
  }, []);

  const structures = useMemo(() => [
    { type: 'shack', pos: [15, 0, 15], rot: 0.5 },
    { type: 'shack', pos: [-25, 0, -30], rot: -1.2 },
    { type: 'wall', pos: [0, 0, -10], rot: 0 },
    { type: 'wall', pos: [10, 0, 40], rot: Math.PI / 2 },
    { type: 'wall', pos: [-40, 0, 10], rot: 0.8 },
  ], []);

  const arrowPositions = useMemo(() => [
    [0, 0.1, 0], [20, 0.1, -10], [-20, 0.1, 20], [30, 0.1, -30], [-30, 0.1, -10]
  ] as [number, number, number][], []);

  return (
    <>
      <mesh rotation={[-Math.PI / 2, 0, 0]} receiveShadow position={[0, 0, 0]}>
        <planeGeometry args={[400, 400]} />
        <meshStandardMaterial color="#050505" roughness={1} />
      </mesh>
      {trees.map(t => <Tree key={t.id} position={t.pos} />)}
      {structures.map((s, i) => (
        s.type === 'shack' 
          ? <Shack key={i} position={s.pos as any} rotation={s.rot} /> 
          : <Wall key={i} position={s.pos as any} rotation={s.rot} />
      ))}
      {arrowPositions.map((pos, i) => (
        <DirectionalArrow key={i} position={pos} pagePositions={activePagePositions} />
      ))}
      {pageDefinitions.map((page) => (
        <Page 
          key={page.id} 
          position={page.pos} 
          onCollect={() => onCollectPage(page.id)} 
        />
      ))}
    </>
  );
};

const Controller = ({ onDeath, setStaticAmount, pagesCollected, flashlightOn, activePagePositions, onUpdateNearestAngle }: any) => {
  const { camera, scene } = useThree();
  const moveSpeed = 0.12;
  const keys = useRef<{ [key: string]: boolean }>({});
  const slenderPos = useRef(new THREE.Vector3(30, 0, 30));
  const lastTeleport = useRef(0);

  const lightRef = useRef<THREE.SpotLight>(null!);
  const targetRef = useRef<THREE.Object3D>(new THREE.Object3D());

  useEffect(() => {
    scene.add(targetRef.current);
    const down = (e: KeyboardEvent) => keys.current[e.code] = true;
    const up = (e: KeyboardEvent) => keys.current[e.code] = false;
    window.addEventListener('keydown', down);
    window.addEventListener('keyup', up);
    return () => {
      window.removeEventListener('keydown', down);
      window.removeEventListener('keyup', up);
      scene.remove(targetRef.current);
    };
  }, [scene]);

  useFrame((state) => {
    const moveDir = new THREE.Vector3();
    const front = Number(keys.current['KeyW'] || 0) - Number(keys.current['KeyS'] || 0);
    const side = Number(keys.current['KeyD'] || 0) - Number(keys.current['KeyA'] || 0);

    if (front !== 0 || side !== 0) {
      const cameraDir = new THREE.Vector3();
      camera.getWorldDirection(cameraDir);
      cameraDir.y = 0;
      cameraDir.normalize();
      const cameraSide = new THREE.Vector3().crossVectors(cameraDir, new THREE.Vector3(0, 1, 0)).normalize();
      moveDir.addScaledVector(cameraDir, front * moveSpeed);
      moveDir.addScaledVector(cameraSide, side * moveSpeed);
      camera.position.add(moveDir);
    }
    camera.position.y = 1.7;

    const lookAtPos = new THREE.Vector3(0, 0, -1).applyQuaternion(camera.quaternion).add(camera.position);
    targetRef.current.position.copy(lookAtPos);
    if (lightRef.current) {
        lightRef.current.position.copy(camera.position);
        lightRef.current.target = targetRef.current;
    }

    const dist = camera.position.distanceTo(slenderPos.current);
    const lookDir = new THREE.Vector3();
    camera.getWorldDirection(lookDir);
    const toSlender = new THREE.Vector3().subVectors(slenderPos.current, camera.position).normalize();
    const dot = lookDir.dot(toSlender);

    let currentStatic = 0;
    if (dist < 25) {
      const multiplier = 1 + (pagesCollected * 0.4);
      currentStatic = (Math.max(0, (25 - dist) / 25) * multiplier);
      if (dot > 0.75) {
        currentStatic *= 4;
      }
    }
    setStaticAmount(Math.min(1, currentStatic));

    if (dist < 3) {
      onDeath();
    }

    // Nearest Page UI Indicator Angle
    if (activePagePositions.length > 0) {
      let closest = activePagePositions[0];
      let minDist = camera.position.distanceTo(closest);
      for (const p of activePagePositions) {
        const d = camera.position.distanceTo(p);
        if (d < minDist) {
          minDist = d;
          closest = p;
        }
      }

      const playerFwd = new THREE.Vector3(0, 0, -1).applyQuaternion(camera.quaternion);
      playerFwd.y = 0;
      playerFwd.normalize();

      const toPage = new THREE.Vector3().subVectors(closest, camera.position);
      toPage.y = 0;
      toPage.normalize();

      // Signed angle around Y axis
      const angle = Math.atan2(toPage.x, toPage.z) - Math.atan2(playerFwd.x, playerFwd.z);
      onUpdateNearestAngle(angle);
    } else {
      onUpdateNearestAngle(null);
    }

    const now = state.clock.getElapsedTime();
    const teleportCooldown = Math.max(1.5, 8 - pagesCollected);
    if (now - lastTeleport.current > teleportCooldown) {
      const angle = Math.random() * Math.PI * 2;
      const spawnDist = Math.max(6, 20 - pagesCollected * 2);
      slenderPos.current.set(camera.position.x + Math.cos(angle) * spawnDist, 0, camera.position.z + Math.sin(angle) * spawnDist);
      lastTeleport.current = now;
    }
  });

  return (
    <>
      <PointerLockControls />
      <SlenderMan position={slenderPos.current} />
      <spotLight ref={lightRef} intensity={flashlightOn ? 45 : 0} distance={30} angle={0.45} penumbra={0.6} color="#fffaf0" castShadow />
      <primitive object={camera} />
    </>
  );
};

